@startuml
class Duck {
    +{abstract} display() void
    +quack() void
    +swim() void
    +fly() void
}

class WildDuck {
    -display() void
}

class PekingDuck {
    -display() void
    -fly() void
}

class ToyDuck {
    -display() void
    -quack() void
    -swim() void
    -fly() void
}

WildDuck --|> Duck : extends
PekingDuck --|> Duck : extends
ToyDuck --|> Duck : extends

note top of Duck #Aqua:A# 
end note 

note bottom of WildDuck #LightGreen:C#  
end note  

note left of  PekingDuck   #PaleTurquoise:B#   
end note   

skinparam classAttributeIconSize false


@enduml
